module RefModule(C, PRE, CLR, D, Q);parameter INIT = 0; 
  input C, PRE, CLR, D; 
  output reg Q; 
  initial begin 
  Q <= INIT; 
  end 
    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge C, posedge PRE, posedge CLR or posedge dbg_halt) begin 
  if (CLR == 1) 
  Q <= 0; 
  else if (PRE == 1) 
  Q <= 1; 
  else 
  Q <= D; 
  end 
 endmodule
